=<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body {
      font-family: Arial, Helvetica, sans-serif;
      line-height: 1.6;
      color: #333333;
      margin: 0;
      padding: 0;
      background-color: #ffffff;
    }
    .container {
      max-width: 650px;
      margin: 0 auto;
      padding: 40px 30px;
    }
    .header {
      border-bottom: 3px solid #1976d2;
      padding-bottom: 20px;
      margin-bottom: 30px;
    }
    .company-name {
      font-size: 24px;
      font-weight: bold;
      color: #1976d2;
      margin: 0 0 5px 0;
    }
    .company-tagline {
      font-size: 14px;
      color: #666666;
      margin: 0;
    }
    h1 {
      color: #1976d2;
      font-size: 22px;
      margin: 0 0 20px 0;
    }
    .notice-box {
      background-color: #e3f2fd;
      border-left: 4px solid #1976d2;
      padding: 15px 20px;
      margin: 25px 0;
    }
    .notice-box p {
      margin: 5px 0;
      font-size: 15px;
    }
    .invoice-details {
      background-color: #f5f5f5;
      padding: 20px;
      border-radius: 5px;
      margin: 25px 0;
    }
    .invoice-details table {
      width: 100%;
      border-collapse: collapse;
    }
    .invoice-details td {
      padding: 8px 0;
      font-size: 15px;
    }
    .invoice-details td:first-child {
      color: #666666;
      width: 45%;
    }
    .invoice-details td:last-child {
      font-weight: bold;
      text-align: right;
    }
    .amount-due {
      font-size: 20px;
      color: #1976d2;
    }
    .payment-section {
      background-color: #fff3cd;
      border-left: 4px solid #ffc107;
      padding: 20px;
      margin: 25px 0;
    }
    .payment-section h2 {
      color: #333333;
      font-size: 18px;
      margin: 0 0 15px 0;
    }
    .payment-details {
      font-size: 14px;
      line-height: 1.8;
    }
    .payment-details strong {
      display: inline-block;
      width: 140px;
      color: #666666;
    }
    .footer {
      margin-top: 40px;
      padding-top: 20px;
      border-top: 1px solid #e0e0e0;
      font-size: 13px;
      color: #666666;
      text-align: center;
    }
    .button {
      display: inline-block;
      background-color: #1976d2;
      color: #ffffff;
      padding: 12px 30px;
      text-decoration: none;
      border-radius: 5px;
      font-weight: bold;
      margin: 20px 0;
    }
    @media print {
      body { background-color: #ffffff; }
      .button { display: none; }
    }
  </style>
</head>
<body>
  <div class="container">
    <!-- Header -->
    <div class="header">
      <p class="company-name">{{$('Your Company Details').first().json['Company Name']}}</p>
      <p class="company-tagline">Software Development & Automation Solutions</p>
    </div>

    <!-- Main Content -->
    <h1>Upcoming Payment Reminder</h1>

    <p>Dear {{$json['Name (from Invoice Clients)']}},</p>

    <p>This is a friendly reminder that payment for the following invoice will be due soon:</p>

    <!-- Notice Box -->
    <div class="notice-box">
      <p><strong>Invoice #{{$json.Invoice['Invoice Id']}}</strong> is due on <strong>{{$json.Invoice['Due Date']}}</strong></p>
      <p>That's in <strong>{{$('Config').first().json['Days before Due Date for reminder']}} days</strong> from today.</p>
    </div>

    <!-- Invoice Details -->
    <div class="invoice-details">
      <table>
        <tr>
          <td>Invoice Number:</td>
          <td>{{$json.Invoice['Invoice Id']}}</td>
        </tr>
        <tr>
          <td>Issue Date:</td>
          <td>{{$json.Invoice['Issue Date']}}</td>
        </tr>
        <tr>
          <td>Due Date:</td>
          <td>{{$json.Invoice['Due Date']}}</td>
        </tr>
        <tr style="border-top: 2px solid #dddddd;">
          <td style="padding-top: 15px;">Amount Due:</td>
          <td class="amount-due" style="padding-top: 15px;">{{$json.Invoice.Amount}} PLN</td>
        </tr>
      </table>
    </div>

    <!-- Payment Information -->
    <div class="payment-section">
      <h2>💳 Payment Details</h2>
      <div class="payment-details">
        <p><strong>Bank Name:</strong> {{$('Your Company Details').first().json['Bank Name']}}</p>
        <p><strong>Account Number:</strong> {{$('Your Company Details').first().json['Bank Account Number']}}</p>
        <p><strong>SWIFT Code:</strong> {{$('Your Company Details').first().json['Swift Code']}}</p>
        <p><strong>Payment Reference:</strong> {{$json.Invoice['Invoice Id']}}</p>
      </div>
    </div>

    <p>To ensure uninterrupted service, please process payment before the due date. If you have already sent payment, please disregard this reminder.</p>

    <p>If you have any questions or need assistance, please don't hesitate to contact us:</p>

    <p>
      <strong>Email:</strong> {{$('Your Company Details').first().json['Email']}}<br>
      <strong>Phone:</strong> {{$('Your Company Details').first().json['Phone']}}<br>
      <strong>Office Hours:</strong> Mon-Fri, 9:00 AM - 5:00 PM CET
    </p>

    <p>Thank you for your business!</p>

    <p>
      Best regards,<br>
      <strong>Accounts Receivable Team</strong><br>

    </p>

    <!-- Footer -->
    <div class="footer">
      <p>{{$('Your Company Details').first().json['Company Name']}} | {{$('Your Company Details').first().json['Country Code']}} | {{$('Your Company Details').first().json['City']}}, {{$('Your Company Details').first().json['Street']}} | {{$('Your Company Details').first().json['Postal Code']}}</p>
      <p>TIN (Tax Identification Number): {{$('Your Company Details').first().json['TIN (Tax Identification Number)']}}</p>
      <p>This is an automated reminder. Please do not reply to this message.</p>
    </div>
  </div>
</body>
</html>

